+// ============================================================================
+// Local Bitonic Sort (within workgroup)
+// ============================================================================
+
+struct LocalSortParams {
+    size: u32,       // Total number of elements
+    stage: u32,      // Current bitonic stage
+    step: u32,       // Current step within stage
+    ascending: u32,  // 1 = ASC, 0 = DESC
