+        keys[idx2] = shared_keys[tid + 256u];
+        indices[idx2] = shared_indices[tid + 256u];
+    }
+}
+
+// ============================================================================
+// Global Bitonic Merge (across workgroups)
+// ============================================================================
+
+struct MergeParams {
+    size: u32,
+    stage: u32,      // 2^stage = block size
+    step: u32,       // Current step (distance between compared elements)
+    ascending: u32,
+}
